{
  "answer_status": "supported",
  "conclusion": "Les gains de cession de valeurs mobilières sont imposables en France pour les résidents fiscaux français.",
  "justification_bullets": [
    "Les résidents fiscaux français sont imposables sur l'ensemble de leurs revenus, y compris les gains de cession de valeurs mobilières [1].",
    "Les gains de cession de titres, même déposés hors de France, sont imposables en France pour les résidents [1]."
  ],
  "limits": "Les extraits ne précisent pas le taux ni le barème applicables aux plus-values."
}

{
  "answer_status": "supported",
  "conclusion": "Les sociétés doivent être soumises à l'IS de droit commun et détenir 95% du capital des filiales.",
  "justification_bullets": [
    "Seules les sociétés soumises à l'IS dans les conditions de droit commun peuvent faire partie du groupe [1].",
    "La société mère doit détenir directement ou indirectement 95% ou plus du capital des filiales de manière continue [3].",
    "Les sociétés exonérées d'IS ne peuvent pas faire partie d'un groupe [1]."
  ],
  "limits": "Les extraits ne couvrent pas toutes les conditions (ex: durée d'exercice, option)."
}

{
  "answer_status": "supported",
  "conclusion": "Le barème progressif s'applique au revenu par part, puis multiplié par le nombre de parts.",
  "justification_bullets": [
    "Le revenu imposable est divisé par le nombre de parts (1 part pour un célibataire) [2].",
    "Le barème progressif est appliqué au revenu par part [5].",
    "L'impôt brut est obtenu en multipliant le résultat par le nombre de parts [5]."
  ],
  "limits": "Les tranches et taux du barème ne sont pas détaillés dans les extraits."
}

{
  "answer_status": "supported",
  "conclusion": "TVA française au taux de 8,5% (taux normal Martinique) car prestation de services B2C.",
  "justification_bullets": [
    "La Martinique applique la TVA avec un taux normal de 8,5% [1].",
    "Pour les prestations de services, la Martinique n'est pas un territoire tiers [2].",
    "Le prestataire est établi en France métropolitaine, donc pas d'autoliquidation [2]."
  ],
  "limits": "Ne couvre pas les éventuelles exonérations spécifiques aux dictionnaires en ligne."
}
